def classify_score(score):
    if not isinstance(score, (int, float)) or score < 0 or score > 100:
        return 'Invalid'
    if score >= 90:
        return 'A'
    elif score >= 80:
        return 'B'
    elif score >= 70:
        return 'C'
    elif score >= 60:
        return 'D'
    else:
        return 'F'

