def calculate_weighted_average(scores, weights):
    total = 0
    weight_sum = 0
    for assignment in scores:
        if assignment in weights:
            total += scores[assignment] * weights[assignment]
            weight_sum += weights[assignment]
    if weight_sum == 0:
        return 0
    return total / weight_sum

from flask import Flask, render_template

app = Flask(__name__)

@app.route('/')
def home():
    return '<h1>Welcome to the Quiz App</h1>'

@app.route('/quiz')
def quiz():
    questions = [
        'What is 2 + 2?',
        'What is the capital of France?',
        'What language are we learning?'
    ]
    return render_template('quiz.html', questions=questions)

if __name__ == '__main__':
    app.run(debug=True)

A route is a URL pattern mapped to a Python function. When a user visits that URL, Flask calls the function and returns its result as the web page.
